import React, { useState, useEffect } from 'react';
import AdminCategories from './AdminCategories';

// Custom Modal Component for "Center of the Screen" Popups
const CenterModal = ({ isOpen, onClose, title, children }) => {
  if (!isOpen) return null;
  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-4">
      <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={onClose}></div>
      <div className="relative bg-white rounded-3xl shadow-2xl w-full max-w-lg p-8 scale-in flex flex-col max-h-[90vh]">
        <h3 className="text-2xl font-black text-slate-800 mb-6">{title}</h3>
        <div className="overflow-y-auto custom-scrollbar flex-1">{children}</div>
      </div>
    </div>
  );
};

export default function Admin() {
  const [isAuth, setIsAuth] = useState(false);
  const [password, setPassword] = useState('');
  const [activeTab, setActiveTab] = useState('events');

  // Modal State
  const [modalConfig, setModalConfig] = useState({ isOpen: false, title: '', content: null });

  // Data States
  const [events, setEvents] = useState([]);
  const [institutes, setInstitutes] = useState([]);
  const [ticker, setTicker] = useState([]);
  const [inquiryNumber, setInquiryNumber] = useState('');

  // Form States (for creating/editing)
  const [eventForm, setEventForm] = useState({ id: null, month: '', day: '', title: '', desc: '', type: '', isFeatured: false });
  const [instituteForm, setInstituteForm] = useState({ id: null, name: '', desc: '' });
  const [newAdminForm, setNewAdminForm] = useState({ username: '', pass: '' });
  const [tickerForm, setTickerForm] = useState('');

  // Initial Load
  useEffect(() => {
    // Events
    const storedEvents = localStorage.getItem('indus_events');
    if (storedEvents) {
      setEvents(JSON.parse(storedEvents));
    } else {
      const defEvents = [
        { id: 1, month: 'JAN', day: '05', title: 'INDUS CUP 2K26', desc: 'Stand a Chance to Win Cash Prizes up to ₹10,00,000', type: 'Sports Fest', isFeatured: true },
        { id: 2, month: 'FEB', day: '15', title: 'Indus Hackathon 2025', desc: 'Join the ultimate 48-hour coding challenge at CSE Department.', type: 'Academic', isFeatured: false }
      ];
      setEvents(defEvents);
      localStorage.setItem('indus_events', JSON.stringify(defEvents));
    }

    // Institutes
    const storedInst = localStorage.getItem('indus_institutes');
    if (storedInst) {
      setInstitutes(JSON.parse(storedInst));
    } else {
      const defInst = [
        { id: 1, name: 'IITE – Indus Institute of Technology & Engineering', desc: 'Upgrading technical skills as per industry requirements.' },
        { id: 2, name: 'IAS – Indus Architecture School', desc: 'Shaping the built environment through excellence.' },
        { id: 3, name: 'IDS – Indus Design School', desc: 'Fostering creativity and innovation in specialized design.' },
        { id: 4, name: 'IIICT – Indus Institute of Info. & Comm. Technology', desc: 'Leading the way in computing and IT research.' },
        { id: 5, name: 'IIMS – Indus Institute of Management Studies', desc: 'Where Practice Meets Theory in business management.' },
        { id: 6, name: 'IISHLS – Indus Institute of Sci. Humanities & Lib. Studies', desc: 'Interdisciplinary pursuit of sciences and humanities.' },
        { id: 7, name: 'IISS – Indus Institute of Special Studies', desc: 'Integrating traditional values and ethos.' },
        { id: 8, name: 'IIPR – Indus Institute of Pharmacy and Research', desc: 'High-quality education in pharmaceutical sciences.' },
        { id: 9, name: 'IIATE – Indus Institute of Aviation Tech & Engineering', desc: 'Specialized training in aviation and aerospace.' },
        { id: 10, name: 'IAGNI – Indus Advance Green Nanotechnology Institute', desc: 'Cutting-edge research in sustainable nanotechnology.' },
      ];
      setInstitutes(defInst);
      localStorage.setItem('indus_institutes', JSON.stringify(defInst));
    }

    // General Settings (Ticker & Inquiry)
    const storedTicker = localStorage.getItem('indus_ticker');
    if (storedTicker) setTicker(JSON.parse(storedTicker));
    else setTicker(["⭐ INDUS CUP 2K26! Win Cash Prizes up to ₹10,00,000! ⭐", "🚀 Hackathon 2025 by CSE Department - Register Now! 🚀"]);

    setInquiryNumber(localStorage.getItem('indus_inquiry_number') || '+91 74054 13342');
  }, []);

  // Save Helpers
  const saveEvents = (data) => { setEvents(data); localStorage.setItem('indus_events', JSON.stringify(data)); };
  const saveInstitutes = (data) => { setInstitutes(data); localStorage.setItem('indus_institutes', JSON.stringify(data)); };
  const saveTicker = (data) => { setTicker(data); localStorage.setItem('indus_ticker', JSON.stringify(data)); };

  const handleSettingsSave = () => {
    localStorage.setItem('indus_inquiry_number', inquiryNumber);
    alert('Settings saved successfully!');
  };

  const handleLogin = (e) => {
    e.preventDefault();
    if (password === '0000' || localStorage.getItem(`admin_${password}`)) {
      setIsAuth(true);
    } else {
      alert('Invalid Password');
    }
  };

  const handleCreateAdmin = (e) => {
    e.preventDefault();
    localStorage.setItem(`admin_${newAdminForm.pass}`, newAdminForm.username);
    alert(`Admin ${newAdminForm.username} created successfully!`);
    setNewAdminForm({ username: '', pass: '' });
  };

  const closeModal = () => setModalConfig({ ...modalConfig, isOpen: false });

  const confirmDelete = (type, id, title) => {
    setModalConfig({
      isOpen: true,
      title: 'Confirm Deletion',
      content: (
        <div>
          <p className="text-slate-600 mb-8">Are you sure you want to delete <strong>{title}</strong>? This action cannot be undone.</p>
          <div className="flex gap-4">
            <button onClick={closeModal} className="flex-1 py-3 bg-slate-100 rounded-xl font-bold text-slate-600 hover:bg-slate-200">Cancel</button>
            <button 
              onClick={() => {
                if (type === 'event') saveEvents(events.filter(e => e.id !== id));
                if (type === 'institute') saveInstitutes(institutes.filter(i => i.id !== id));
                if (type === 'ticker') saveTicker(ticker.filter((_, idx) => idx !== id));
                if (type === 'category') {
                  const storedCats = localStorage.getItem('indus_categories');
                  if (storedCats) {
                    const cats = JSON.parse(storedCats);
                    localStorage.setItem('indus_categories', JSON.stringify(cats.filter(c => c.id !== id)));
                    window.dispatchEvent(new Event('storage')); // trigger update for AdminCategories
                  }
                }
                closeModal();
              }} 
              className="flex-1 py-3 bg-red-500 rounded-xl font-bold text-white hover:bg-red-600 shadow-[0_4px_15px_rgba(239,68,68,0.3)]"
            >
              Delete
            </button>
          </div>
        </div>
      )
    });
  };

  // --- EVENTS LOGIC ---
  const saveEvent = (e) => {
    e.preventDefault();
    if (eventForm.id) {
      saveEvents(events.map(ev => ev.id === eventForm.id ? { ...eventForm } : ev));
    } else {
      saveEvents([...events, { ...eventForm, id: Date.now() }]);
    }
    setEventForm({ id: null, month: '', day: '', title: '', desc: '', type: '', isFeatured: false });
  };

  // --- INSTITUTES LOGIC ---
  const saveInstitute = (e) => {
    e.preventDefault();
    if (instituteForm.id) {
      saveInstitutes(institutes.map(inst => inst.id === instituteForm.id ? { ...instituteForm } : inst));
    } else {
      saveInstitutes([...institutes, { ...instituteForm, id: Date.now() }]);
    }
    setInstituteForm({ id: null, name: '', desc: '' });
  };


  if (!isAuth) {
    return (
      <div className="flex-1 flex items-center justify-center bg-[#fcfbf9] min-h-screen p-6">
        <div className="bg-white p-12 rounded-[3rem] shadow-2xl max-w-md w-full border border-gray-100 text-center">
          <div className="w-20 h-20 bg-brand-brown/10 rounded-full flex items-center justify-center mx-auto mb-6">
            <svg className="w-10 h-10 text-brand-brown" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
          </div>
          <h2 className="text-3xl font-black text-slate-800 mb-2">Admin Access</h2>
          <p className="text-slate-500 mb-8 font-medium">Use developer pin (0000) or staff code.</p>
          <form onSubmit={handleLogin} className="space-y-6">
            <div>
              <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full bg-slate-50 px-6 py-4 rounded-2xl border-none outline-none focus:ring-2 focus:ring-brand-brown/30 text-center text-2xl tracking-[0.5em] font-bold text-slate-700" placeholder="••••" />
            </div>
            <button type="submit" className="w-full bg-brand-brown text-white font-bold py-4 rounded-2xl hover:scale-[1.02] active:scale-[0.98] transition-transform shadow-[0_10px_30px_-10px_rgba(111,92,78,0.5)]">Authenticate</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="flex-1 bg-[#fcfbf9] min-h-screen overflow-y-auto p-6 md:p-12 relative pb-32">
      <CenterModal isOpen={modalConfig.isOpen} onClose={closeModal} title={modalConfig.title}>
        {modalConfig.content}
      </CenterModal>

      <div className="max-w-6xl mx-auto">
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-12 border-b border-gray-200 pb-8">
          <div>
            <h1 className="text-4xl md:text-5xl font-black text-slate-900 mb-2">Institutional Management</h1>
            <p className="text-slate-500 font-bold text-lg italic">Welcome to the central control panel</p>
          </div>
          <div className="flex gap-4 items-center">
            <button onClick={() => window.location.href = window.location.pathname} className="px-6 py-3 bg-white border border-slate-200 text-slate-600 rounded-xl font-bold hover:bg-slate-50 text-sm transition-all shadow-sm">Return to Website</button>
            <button onClick={() => setIsAuth(false)} className="px-6 py-3 bg-red-100 text-red-600 rounded-xl font-bold hover:bg-red-200 text-sm transition-colors">Terminate Session</button>
          </div>
        </div>

        {/* Navigation Tabs */}
        <div className="flex flex-wrap gap-3 mb-10">
          {[
            { id: 'events', label: 'News & Events' },
            { id: 'institutes', label: 'Our Institutes' },
            { id: 'categories', label: 'Categories & Courses' },
            { id: 'settings', label: 'Global Settings' },
            { id: 'admin', label: 'Personnel Admin' },
          ].map(tab => (
            <button 
              key={tab.id} 
              onClick={() => setActiveTab(tab.id)}
              className={`px-8 py-4 rounded-2xl font-black text-sm uppercase tracking-wider transition-all duration-300 ${activeTab === tab.id ? 'bg-brand-brown text-white shadow-[0_10px_20px_rgba(111,92,78,0.3)] scale-105' : 'bg-white text-slate-400 hover:bg-slate-50 border border-slate-100'}`}
            >
              {tab.label}
            </button>
          ))}
        </div>

        {/* Tab Contents */}
        {activeTab === 'categories' && (
          <AdminCategories confirmDelete={confirmDelete} CenterModal={CenterModal} />
        )}

        {activeTab === 'events' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-10 fade-in">
            <div className="lg:col-span-5">
              <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100 sticky top-10">
                <h3 className="text-2xl font-black mb-8 text-slate-800">{eventForm.id ? 'Edit Event' : 'Provision New Event'}</h3>
                <form onSubmit={saveEvent} className="space-y-6">
                  <div className="grid grid-cols-2 gap-4">
                     <div>
                       <label className="block text-[10px] font-black tracking-widest text-slate-400 uppercase mb-2">Event Month</label>
                       <input required type="text" placeholder="e.g. JAN" value={eventForm.month} onChange={(e) => setEventForm({...eventForm, month: e.target.value.toUpperCase()})} className="w-full bg-slate-50 p-4 rounded-xl outline-none font-bold placeholder:text-slate-300 focus:bg-white focus:ring-2 focus:ring-brand-brown/20 uppercase" maxLength={3} />
                     </div>
                     <div>
                       <label className="block text-[10px] font-black tracking-widest text-slate-400 uppercase mb-2">Event Day</label>
                       <input required type="text" placeholder="e.g. 05" value={eventForm.day} onChange={(e) => setEventForm({...eventForm, day: e.target.value})} className="w-full bg-slate-50 p-4 rounded-xl outline-none font-bold placeholder:text-slate-300 focus:bg-white focus:ring-2 focus:ring-brand-brown/20" maxLength={2} />
                     </div>
                  </div>
                  <div>
                    <label className="block text-[10px] font-black tracking-widest text-slate-400 uppercase mb-2">Event Title</label>
                    <input required type="text" placeholder="Technical Innovation Fair" value={eventForm.title} onChange={(e) => setEventForm({...eventForm, title: e.target.value})} className="w-full bg-slate-50 p-4 rounded-xl outline-none font-bold placeholder:text-slate-300 focus:bg-white focus:ring-2 focus:ring-brand-brown/20" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black tracking-widest text-slate-400 uppercase mb-2">Brief Description</label>
                    <textarea required placeholder="Short exciting description..." value={eventForm.desc} onChange={(e) => setEventForm({...eventForm, desc: e.target.value})} className="w-full bg-slate-50 p-4 rounded-xl outline-none font-bold placeholder:text-slate-300 focus:bg-white focus:ring-2 focus:ring-brand-brown/20 min-h-[100px] resize-none"></textarea>
                  </div>
                  <div className="grid grid-cols-2 gap-4 items-end">
                    <div>
                      <label className="block text-[10px] font-black tracking-widest text-slate-400 uppercase mb-2">Category Flag</label>
                      <input required type="text" placeholder="e.g. ACADEMIC" value={eventForm.type} onChange={(e) => setEventForm({...eventForm, type: e.target.value.toUpperCase()})} className="w-full bg-slate-50 p-4 rounded-xl outline-none font-bold placeholder:text-slate-300 focus:bg-white focus:ring-2 focus:ring-brand-brown/20" />
                    </div>
                    <div className="flex items-center h-[56px] pl-2 cursor-pointer" onClick={() => setEventForm({...eventForm, isFeatured: !eventForm.isFeatured})}>
                       <div className={`w-6 h-6 rounded border-2 border-brand-brown/30 flex items-center justify-center mr-3 transition-colors ${eventForm.isFeatured ? 'bg-brand-brown border-brand-brown' : 'bg-transparent'}`}>
                         {eventForm.isFeatured && (<svg className="w-4 h-4 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>)}
                       </div>
                       <span className="font-bold text-slate-600 text-sm">Featured Badge</span>
                    </div>
                  </div>
                  <div className="pt-4 flex gap-4">
                    {eventForm.id && <button type="button" onClick={() => setEventForm({ id: null, month: '', day: '', title: '', desc: '', type: '', isFeatured: false })} className="flex-1 py-4 font-bold text-slate-500 bg-slate-100 rounded-xl hover:bg-slate-200 transition-colors">Cancel</button>}
                    <button type="submit" className="flex-1 bg-brand-brown text-white font-bold py-4 rounded-xl hover:bg-[#5a483d] transition-colors">{eventForm.id ? 'Save Changes' : 'Publish Event'}</button>
                  </div>
                </form>
              </div>
            </div>

            <div className="lg:col-span-7 space-y-4">
              <h3 className="text-xl font-black text-slate-800 border-l-4 border-slate-300 pl-4 uppercase tracking-widest mb-6">Live Directory</h3>
              {events.map(ev => (
                <div key={ev.id} className={`bg-white p-6 rounded-[2rem] shadow-sm flex items-center gap-6 border-l-8 ${ev.isFeatured ? 'border-orange-500' : 'border-slate-300'} hover:-translate-x-2 transition-transform duration-300 group`}>
                   <div className="bg-slate-50 w-20 h-20 rounded-2xl flex flex-col items-center justify-center shrink-0 border border-slate-100">
                     <span className="text-[10px] font-black text-slate-400">{ev.month}</span>
                     <span className="text-2xl font-black text-slate-900 leading-none">{ev.day}</span>
                   </div>
                   <div className="flex-1">
                     <h4 className="text-xl font-black text-slate-900 mb-1">{ev.title}</h4>
                     <p className="text-[10px] font-black tracking-widest text-[#1a56db] uppercase">{ev.type}</p>
                   </div>
                   <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity pr-2">
                     <button onClick={() => setEventForm(ev)} className="w-12 h-12 bg-slate-50 rounded-xl flex items-center justify-center text-slate-400 hover:text-brand-brown hover:bg-brand-brown/10 transition-colors"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg></button>
                     <button onClick={() => confirmDelete('event', ev.id, ev.title)} className="w-12 h-12 bg-red-50/50 rounded-xl flex items-center justify-center text-red-400 hover:text-white hover:bg-red-500 transition-colors"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                   </div>
                </div>
              ))}
              {events.length === 0 && <div className="text-center py-20 opacity-50"><p className="text-xl font-bold">No Events Found</p></div>}
            </div>
          </div>
        )}

        {activeTab === 'institutes' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-10 fade-in">
            <div className="lg:col-span-5">
              <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100 sticky top-10">
                <h3 className="text-2xl font-black mb-8 text-slate-800">{instituteForm.id ? 'Edit Institute' : 'Add Institute'}</h3>
                <form onSubmit={saveInstitute} className="space-y-6">
                  <div>
                    <label className="block text-[10px] font-black tracking-widest text-slate-400 uppercase mb-2">Institute Name & Prefix</label>
                    <input required type="text" placeholder="IITE - Indus Institute..." value={instituteForm.name} onChange={(e) => setInstituteForm({...instituteForm, name: e.target.value})} className="w-full bg-slate-50 p-4 rounded-xl outline-none font-bold placeholder:text-slate-300 focus:bg-white focus:ring-2 focus:ring-brand-brown/20" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black tracking-widest text-slate-400 uppercase mb-2">Tagline / Description</label>
                    <textarea required placeholder="Shaping the built environment..." value={instituteForm.desc} onChange={(e) => setInstituteForm({...instituteForm, desc: e.target.value})} className="w-full bg-slate-50 p-4 rounded-xl outline-none font-bold placeholder:text-slate-300 focus:bg-white focus:ring-2 focus:ring-brand-brown/20 min-h-[100px] resize-none"></textarea>
                  </div>
                  <div className="pt-4 flex gap-4">
                    {instituteForm.id && <button type="button" onClick={() => setInstituteForm({ id: null, name: '', desc: '' })} className="flex-1 py-4 font-bold text-slate-500 bg-slate-100 rounded-xl hover:bg-slate-200 transition-colors">Cancel</button>}
                    <button type="submit" className="flex-1 bg-brand-brown text-white font-bold py-4 rounded-xl hover:bg-[#5a483d] transition-colors">{instituteForm.id ? 'Save Changes' : 'Add Institute'}</button>
                  </div>
                </form>
              </div>
            </div>

            <div className="lg:col-span-7 space-y-4">
              <h3 className="text-xl font-black text-slate-800 border-l-4 border-slate-300 pl-4 uppercase tracking-widest mb-6">Our Institutes Directory</h3>
              {institutes.map(inst => (
                <div key={inst.id} className="bg-white p-6 rounded-[2rem] shadow-sm flex items-center justify-between border border-slate-50 hover:border-slate-200 transition-all group">
                   <div className="flex-1">
                     <h4 className="text-lg font-black text-slate-900 mb-1">{inst.name}</h4>
                     <p className="text-sm font-medium text-slate-500">{inst.desc}</p>
                   </div>
                   <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity pl-4">
                     <button onClick={() => setInstituteForm(inst)} className="w-12 h-12 bg-slate-50 rounded-xl flex items-center justify-center text-slate-400 hover:text-brand-brown hover:bg-brand-brown/10 transition-colors"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg></button>
                     <button onClick={() => confirmDelete('institute', inst.id, inst.name)} className="w-12 h-12 bg-red-50/50 rounded-xl flex items-center justify-center text-red-400 hover:text-white hover:bg-red-500 transition-colors"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                   </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'settings' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-10 fade-in">
            <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100 flex flex-col">
              <h3 className="text-2xl font-black mb-8 text-slate-800">Global Website Settings</h3>

              <div className="mb-8">
                <label className="block text-[10px] font-black tracking-widest text-[#1a56db] uppercase mb-4">Central Inquiry Number</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">📞</span>
                  <input type="text" value={inquiryNumber} onChange={(e) => setInquiryNumber(e.target.value)} className="w-full bg-slate-50 pl-12 pr-4 py-4 rounded-xl outline-none font-bold focus:bg-white focus:ring-2 focus:ring-brand-brown/20 text-slate-800 text-lg" />
                </div>
                <p className="mt-3 text-xs text-slate-400 font-bold">This updates the contact number shown at the bottom of program details sidebars and other global areas.</p>
              </div>

              <div className="mt-auto pt-8 border-t border-slate-100">
                <button onClick={handleSettingsSave} className="w-full py-4 bg-slate-900 text-white rounded-xl font-bold shadow-[0_4px_20px_rgba(0,0,0,0.2)] hover:scale-[1.02] transition-transform">Save Global Settings</button>
              </div>
            </div>

            <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100 flex flex-col">
              <h3 className="text-xl font-black mb-6 text-slate-800 border-l-4 border-orange-400 pl-4">Scrolling News Ticker</h3>
              <p className="text-sm font-bold text-slate-500 mb-6">Manage the alerts scrolling horizontally at the bottom of the home screen.</p>

              <form onSubmit={(e) => { e.preventDefault(); if (tickerForm) { saveTicker([...ticker, tickerForm]); setTickerForm(''); } }} className="flex gap-4 mb-8">
                <input required type="text" placeholder="e.g. ⭐ New Admissions Open Now!" value={tickerForm} onChange={(e) => setTickerForm(e.target.value)} className="flex-1 bg-slate-50 px-4 py-3 rounded-xl outline-none font-bold text-sm focus:ring-2 focus:ring-brand-brown/20" />
                <button type="submit" className="px-6 bg-brand-brown text-white rounded-xl font-bold hover:bg-[#5a483d] transition-colors">Add</button>
              </form>

              <div className="space-y-3 flex-1 overflow-y-auto max-h-[300px] custom-scrollbar pr-2">
                {ticker.map((item, idx) => (
                  <div key={idx} className="flex items-center gap-4 bg-slate-50 p-4 rounded-xl group/t">
                    <p className="flex-1 text-sm font-bold text-slate-700 truncate">{item}</p>
                    <button onClick={() => confirmDelete('ticker', idx, 'this ticker text')} className="w-8 h-8 rounded-lg flex items-center justify-center text-slate-400 hover:text-white hover:bg-red-500 transition-colors opacity-0 group-hover/t:opacity-100"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg></button>
                  </div>
                ))}
            </div>
            </div>
          </div>
        )}

        {activeTab === 'admin' && (
          <div className="max-w-xl mx-auto bg-white p-10 rounded-[2.5rem] shadow-sm border border-slate-100 fade-in mt-10">
            <h3 className="text-3xl font-black text-slate-800 mb-8 border-b border-gray-100 pb-6">Create New Administrator</h3>
            <form onSubmit={handleCreateAdmin} className="space-y-6">
              <div>
                <label className="block text-[10px] font-black tracking-widest text-[#1a56db] uppercase mb-2">Full Name / Identifier</label>
                <input required type="text" placeholder="John Doe" value={newAdminForm.username} onChange={(e) => setNewAdminForm({...newAdminForm, username: e.target.value})} className="w-full bg-slate-50 p-4 rounded-xl outline-none font-bold placeholder:text-slate-300 focus:bg-white focus:ring-2 focus:ring-[#1a56db]/20" />
              </div>
              <div>
                <label className="block text-[10px] font-black tracking-widest text-[#1a56db] uppercase mb-2">Secret PIN / Password</label>
                <input required type="password" placeholder="••••" value={newAdminForm.pass} onChange={(e) => setNewAdminForm({...newAdminForm, pass: e.target.value})} className="w-full bg-slate-50 p-4 rounded-xl outline-none font-bold placeholder:text-slate-300 focus:bg-white focus:ring-2 focus:ring-[#1a56db]/20 text-xl tracking-[0.3em]" />
              </div>
              <button type="submit" className="w-full bg-[#1a56db] text-white font-bold py-4 rounded-xl hover:bg-[#1546b5] transition-colors mt-4">Register Admin Portal Access</button>
            </form>
          </div>
        )}

      </div>
    </div>
  );
}
